class Trie:
	ndef __init__(self):
		self.root = TrieNode()

	def insert(self, word: str) -> None:
		current = self.root
		for c in word:
			if current.children.get(c) is None:
				current.children[c] = TrieNode()
			current = current.children[c]
			if c == word[-1]:
				current.isEndOfWord = True

	def main():
		trie = Trie()
		trie.insert("hello")

